<span class="line"><span style="color:#CDD6F4;">            message </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">generate_commit_message</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">changed_files</span><span style="color:#9399B2;">)</span></span>
